     * agreements, [`StackError::Http`] on any other non-2xx response,
     * [`StackError::Decode`] on malformed JSON, or [`StackError::Network`] on
     * transport failure.
     */
    func fetchAppReviewDetail(versionId: String) async throws  -> AppReviewDetailInfo?
    
    /**
