    return
        try  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_stack_core_fn_method_syncservice_sync_apps(
                    self.uniffiCloneHandle()
                    
                )
            },
            pollFunc: ffi_stack_core_rust_future_poll_rust_buffer,
